import{c as t,Q as e,j as l,m as i}from"./chunks/framework.Bhbi9jCp.js";const b=JSON.parse('{"title":"低延迟直播","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/27-低延迟直播.md","filePath":"mediaTechLearning/27-低延迟直播.md","lastUpdated":1780887690000}'),n={name:"mediaTechLearning/27-低延迟直播.md"};function s(r,a,d,o,p,h){return e(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="低延迟直播" tabindex="-1">低延迟直播 <a class="header-anchor" href="#低延迟直播" aria-label="Permalink to &quot;低延迟直播&quot;">​</a></h1><p>低延迟直播不是把 HLS 分片切短那么简单。延迟来自采集、编码、网络、分发、播放器每一段。</p><blockquote><p>一句话先记住:<strong>低延迟是端到端预算问题</strong>。你省了分片延迟,但编码器、CDN、播放器缓冲不改,总延迟还是下不来。</p></blockquote><hr><h2 id="一、延迟拆解" tabindex="-1">一、延迟拆解 <a class="header-anchor" href="#一、延迟拆解" aria-label="Permalink to &quot;一、延迟拆解&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>采集延迟</span></span>
<span class="line"><span>  + 编码延迟</span></span>
<span class="line"><span>  + 上行网络</span></span>
<span class="line"><span>  + 服务端处理</span></span>
<span class="line"><span>  + CDN 分发</span></span>
<span class="line"><span>  + 播放器缓冲</span></span>
<span class="line"><span>  + 解码渲染</span></span></code></pre></div><p>每段都要量。只看播放器延迟没有意义。</p><hr><h2 id="二、延迟档位" tabindex="-1">二、延迟档位 <a class="header-anchor" href="#二、延迟档位" aria-label="Permalink to &quot;二、延迟档位&quot;">​</a></h2><table tabindex="0"><thead><tr><th>档位</th><th>技术</th><th>场景</th></tr></thead><tbody><tr><td>10s+</td><td>普通 HLS</td><td>大规模稳定直播</td></tr><tr><td>3-8s</td><td>短分片 HLS / FLV</td><td>普通互动直播</td></tr><tr><td>1-3s</td><td>LL-HLS / WebRTC / 优化 FLV</td><td>低延迟直播</td></tr><tr><td>&lt;1s</td><td>WebRTC</td><td>强互动</td></tr></tbody></table><p>延迟越低,系统越贵、越脆、越难缓存。</p><hr><h2 id="三、降低编码延迟" tabindex="-1">三、降低编码延迟 <a class="header-anchor" href="#三、降低编码延迟" aria-label="Permalink to &quot;三、降低编码延迟&quot;">​</a></h2><p>策略:</p><ul><li>减少 B 帧</li><li>缩短 GOP</li><li>使用低延迟编码参数</li><li>控制分辨率和帧率</li><li>硬编码实测</li></ul><p>低延迟参数通常会牺牲压缩效率。码率会上升。</p><hr><h2 id="四、降低分发延迟" tabindex="-1">四、降低分发延迟 <a class="header-anchor" href="#四、降低分发延迟" aria-label="Permalink to &quot;四、降低分发延迟&quot;">​</a></h2><p>普通 HLS 的延迟主要来自:</p><ul><li>分片生成</li><li>清单刷新</li><li>CDN 缓存</li><li>播放器安全缓冲</li></ul><p>LL-HLS 用 partial segment 等机制降低延迟,但要求服务端、CDN、播放器都支持。不是改一个参数就完事。</p><hr><h2 id="五、webrtc-低延迟" tabindex="-1">五、WebRTC 低延迟 <a class="header-anchor" href="#五、webrtc-低延迟" aria-label="Permalink to &quot;五、WebRTC 低延迟&quot;">​</a></h2><p>WebRTC 优势:</p><ul><li>小缓冲</li><li>拥塞控制</li><li>RTCP 反馈</li><li>适合交互</li></ul><p>代价:</p><ul><li>大规模分发复杂</li><li>TURN/SFU/边缘成本</li><li>弱网下更容易暴露质量问题</li></ul><p>强互动用 WebRTC,纯观看优先 HLS/CDN。</p><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>只改 hls_time</strong>——端到端延迟不一定降。</li><li><strong>低延迟不监控端到端时间</strong>——不知道省在哪里。</li><li><strong>不改播放器缓冲</strong>——前面省的全被播放器吃掉。</li><li><strong>低延迟还追高压缩率</strong>——通常冲突。</li><li><strong>所有房间默认低延迟</strong>——成本不必要地上升。</li></ol><p>下一篇:<code>28-音视频质量评估与排障.md</code>。</p>`,32)])])}const u=t(n,[["render",s]]);export{b as __pageData,u as default};
